"use client"
import { useState } from "react"
import { Interface } from "readline"

Interface

const TodoForm = ({addTodo}) => {
  const [todo, setTodo] = useState('')
  const handleAddFormChange = (event) =>{
    setTodo(event.target.value)
  }

  const handleAddTodo = () =>{
    addTodo(todo)
  }

  return (
    <>
      <input type="text" className="border-1 rounded-2xl" onChange={handleAddFormChange} value={todo}/>
      <button onClick={handleAddTodo}>Add</button>
    </>
  )
}

const IndexPage = () => {
  
  const [todos, setTodos] = useState([
    {id: 1, content: "Todo1"},
    {id: 2, content: "Todo2"},
    {id: 3, content: "Todo3"}
  ])

  
  
  const addTodo = () =>{
    setTodos([{id: todos.length + 1, content: todo}, ...todos])
  }

  return (
    <>
    <div>{todo}</div>
      <input type="text" className="border-1 rounded-2xl" onChange={handleAddFormChange}/>
      <button onClick={addTodo}>Add</button>
      <ul>
        {todos.map(todo => <li key={todo.id}>{todo.content}</li>)}
      </ul>
    </>
  )
}
export default IndexPage